// Middleware to protect routes requiring 2FA verification
function require2FA(req, res, next) {
  const userId = req.headers['x-user-id'] || req.body.userId;

  if (!userId) {
    return res.status(401).json({
      success: false,
      message: 'User identification required'
    });
  }

  redisClient.get(verifiedKey(userId))
    .then((verifiedData) => {
      if (!verifiedData) {
        return res.status(403).json({
          success: false,
          message: 'Two-factor authentication required. Please verify your identity.'
        });
      }

      const parsed = JSON.parse(verifiedData);
      if (!parsed.verified) {
        return res.status(403).json({
          success: false,
          message: 'Two-factor authentication not completed.'
        });
      }

      req.twoFactorVerified = true;
      req.twoFactorVerifiedAt = parsed.verifiedAt;
      next();
    })
    .catch((error) => {
      console.error('2FA middleware error:', error);
      return res.status(500).json({
        success: false,
        message: 'Internal server error during 2FA verification check'
      });
    });
}

